import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        even = odd = 0
        for _ in range(N):
            x = int(next(it))
            if x % 2 == 0:
                even += 1
            else:
                odd += 1
        out_lines.append('READY FOR BATTLE' if even > odd else 'NOT READY')
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

